// promotedAfterIndex returns the index after which the promoted item should
// be inserted so it appears centered in the nav bar.
func promotedAfterIndex(cfg linkwell.NavConfig) int {
	vis := navMaxVisible(cfg)
	if vis <= 1 {
		return 0
	}
	return (vis - 1) / 2
}

